class SecureModelDownloader:
    def __init__(self, cache_dir: str = "./model_cache", verify_checksums: bool = True):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.verify_checksums = verify_checksums
        self.trusted_domains = {
            'github.com',
            'githubusercontent.com',
            'pytorch.org',
            'download.pytorch.org',
            'huggingface.co',
            'cdn.huggingface.co'
        }
        
    def _is_trusted_url(self, url: str) -> bool:
        parsed = urlparse(url)
        domain = parsed.netloc.lower()
        return any(trusted in domain for trusted in self.trusted_domains)
    
    def _compute_checksum(self, filepath: Path, algorithm: str = 'sha256') -> str:
        hash_obj = hashlib.new(algorithm)
        with open(filepath, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                hash_obj.update(chunk)
        return hash_obj.hexdigest()
    
    def _verify_checksum(self, filepath: Path, expected_checksum: str, algorithm: str = 'sha256') -> bool:
        actual_checksum = self._compute_checksum(filepath, algorithm)
        return actual_checksum == expected_checksum
    
    def download_model(self, url: str, filename: Optional[str] = None, 
                      expected_checksum: Optional[str] = None,
                      checksum_algorithm: str = 'sha256') -> Path:
        if not self._is_trusted_url(url):
            raise ValueError(f"URL domain not in trusted list: {url}")
        
        if filename is None:
            filename = os.path.basename(urlparse(url).path)
        
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            if expected_checksum and self.verify_checksums:
                if self._verify_checksum(filepath, expected_checksum, checksum_algorithm):
                    print(f"Model already cached and verified: {filepath}")
                    return filepath
                else:
                    warnings.warn(f"Cached model checksum mismatch. Re-downloading...")
                    filepath.unlink()
            else:
                print(f"Model already cached: {filepath}")
                return filepath
        
        print(f"Downloading model from {url}...")
        response = requests.get(url, stream=True, timeout=300, verify=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        downloaded = 0
        
        with open(filepath, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)
                    downloaded += len(chunk)
                    if total_size > 0:
                        progress = (downloaded / total_size) * 100
                        print(f"\rProgress: {progress:.1f}%", end='')
        
        print("\nDownload complete.")
        
        if expected_checksum and self.verify_checksums:
            if not self._verify_checksum(filepath, expected_checksum, checksum_algorithm):
                filepath.unlink()
                raise ValueError("Downloaded file checksum verification failed!")
            print("Checksum verified successfully.")
        
        return filepath
    
    def load_checkpoint(self, filepath: Path, map_location: str = 'cpu',
                       weights_only: bool = True) -> Dict[str, Any]:
        if not filepath.exists():
            raise FileNotFoundError(f"Model file not found: {filepath}")
        
        try:
            checkpoint = torch.load(filepath, map_location=map_location, 
                                   weights_only=weights_only)
            return checkpoint
        except Exception as e:
            raise RuntimeError(f"Failed to load checkpoint: {e}")


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


class TransferLearningPipeline:
    def __init__(self, model_name: str = 'resnet50', num_classes: int = 10,
                 device: str = 'cpu', freeze_backbone: bool = True):
        self.model_name = model_name
        self.num_classes = num_classes
        self.device = torch.device(device)
        self.freeze_backbone = freeze_backbone
        self.model = None
        self.downloader = SecureModelDownloader()
        
    def load_pretrained_model(self, custom_url: Optional[str] = None,
                             custom_checkpoint: Optional[str] = None,
                             expected_checksum: Optional[str] = None):
        if custom_url:
            filepath = self.downloader.download_model(
                custom_url, 
                expected_checksum=expected_checksum
            )
            checkpoint = self.downloader.load_checkpoint(filepath, 
                                                        map_location=str(self.device),
                                                        weights_only=True)
            
            if self.model_name == 'resnet50':
                self.model = models.resnet50(weights=None)
            elif self.model_name == 'resnet18':
                self.model = models.resnet18(weights=None)
            elif self.model_name == 'vgg16':
                self.model = models.vgg16(weights=None)
            else:
                raise ValueError(f"Unsupported model: {self.model_name}")
            
            if 'state_dict' in checkpoint:
                self.model.load_state_dict(checkpoint['state_dict'], strict=False)
            else:
                self.model.load_state_dict(checkpoint, strict=False)
        else:
            if self.model_name == 'resnet50':
                self.model = models.resnet50(weights=models.ResNet50_Weights.IMAGENET1K_V1)
            elif self.model_name == 'resnet18':
                self.model = models.resnet18(weights=models.ResNet18_Weights.IMAGENET1K_V1)
            elif self.model_name == 'vgg16':
                self.model = models.vgg16(weights=models.VGG16_Weights.IMAGENET1K_V1)
            else:
                raise ValueError(f"Unsupported model: {self.model_name}")
        
        self._modify_classifier()
        
        if self.freeze_backbone:
            self._freeze_backbone()
        
        self.model = self.model.to(self.device)
        print(f"Model {self.model_name} loaded successfully.")
    
    def _modify_classifier(self):
        if 'resnet' in self.model_name:
            num_features = self.model.fc.in_features
            self.model.fc = nn.Linear(num_features, self.num_classes)
        elif 'vgg' in self.model_name:
            num_features = self.model.classifier[6].in_features
            self.model.classifier[6] = nn.Linear(num_features, self.num_classes)
    
    def _freeze_backbone(self):
        if 'resnet' in self.model_name:
            for param in self.model.parameters():
                param.requires_grad = False
            for param in self.model.fc.parameters():
                param.requires_grad = True
        elif 'vgg' in self.model_name:
            for param in self.model.features.parameters():
                param.requires_grad = False
            for param in self.model.classifier.parameters():
                param.requires_grad = True
    
    def fine_tune(self, train_loader: DataLoader, val_loader: Optional[DataLoader] = None,
                  epochs: int = 10, learning_rate: float = 0.001,
                  optimizer_type: str = 'adam', save_path: Optional[str] = None):
        criterion = nn.CrossEntropyLoss()
        
        if optimizer_type.lower() == 'adam':
            optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()),
                                  lr=learning_rate)
        elif optimizer_type.lower() == 'sgd':
            optimizer = optim.SGD(filter(lambda p: p.requires_grad, self.model.parameters()),
                                 lr=learning_rate, momentum=0.9)
        else:
            raise ValueError(f"Unsupported optimizer: {optimizer_type}")
        
        scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=7, gamma=0.1)
        
        best_acc = 0.0
        
        for epoch in range(epochs):
            print(f"\nEpoch {epoch + 1}/{epochs}")
            print("-" * 40)
            
            self.model.train()
            running_loss = 0.0
            running_corrects = 0
            total_samples = 0
            
            for inputs, labels in train_loader:
                inputs = inputs.to(self.device)
                labels = labels.to(self.device)
                
                optimizer.zero_grad()
                
                outputs = self.model(inputs)
                _, preds = torch.max(outputs, 1)
                loss = criterion(outputs, labels)
                
                loss.backward()
                optimizer.step()
                
                running_loss += loss.item() * inputs.size(0)
                running_corrects += torch.sum(preds == labels.data)
                total_samples += inputs.size(0)
            
            epoch_loss = running_loss / total_samples
            epoch_acc = running_corrects.double() / total_samples
            
            print(f"Train Loss: {epoch_loss:.4f} Acc: {epoch_acc:.4f}")
            
            if val_loader:
                val_acc = self.evaluate(val_loader)
                print(f"Val Acc: {val_acc:.4f}")
                
                if val_acc > best_acc:
                    best_acc = val_acc
                    if save_path:
                        self.save_model(save_path)
                        print(f"Model saved to {save_path}")
            
            scheduler.step()
        
        print(f"\nTraining complete. Best val accuracy: {best_acc:.4f}")
    
    def evaluate(self, data_loader: DataLoader) -> float:
        self.model.eval()
        running_corrects = 0
        total_samples = 0
        
        with torch.no_grad():
            for inputs, labels in data_loader:
                inputs = inputs.to(self.device)
                labels = labels.to(self.device)
                
                outputs = self.model(inputs)
                _, preds = torch.max(outputs, 1)
                
                running_corrects += torch.sum(preds == labels.data)
                total_samples += inputs.size(0)
        
        accuracy = running_corrects.double() / total_samples
        return accuracy.item()
    
    def save_model(self, filepath: str):
        torch.save({
            'model_state_dict': self.model.state_dict(),
            'model_name': self.model_name,
            'num_classes': self.num_classes
        }, filepath)
    
    def load_model(self, filepath: str):
        checkpoint = torch.load(filepath, map_location=self.device, weights_only=True)
        self.model.load_state_dict(checkpoint['model_state_dict'])
        self.model = self.model.to(self.device)


def create_sample_dataset(num_samples: int = 100, num_classes: int = 10):
    data = torch.randn(num_samples, 3, 224, 224)
    labels = torch.randint(0, num_classes, (num_samples,))
    return data, labels


